// Package render produces the file contents for dnsmasq .conf and Caddy
// .caddy outputs (design §4).
package render

import (
	"fmt"
	"strings"
)

// Header marks generated files. Identical across both output types.
const Header = "# GENERATED by splitdns — do not edit. Source: services.yaml"

// CaddyImportFile is the content of splitdns.generated.caddy — the single file
// every host's Caddyfile should import. Order matters: the forward-auth snippet
// and tls snippets must be defined before the site blocks that reference them.
const CaddyImportFile = Header + "\n" +
	"import " + AuthSnippetFilename + "\n" +
	"import tls/*.caddy\n" +
	"import sites/*.caddy\n"

// CaddyImportFilename is the name of the generated import file.
const CaddyImportFilename = "splitdns.generated.caddy"

// AuthSnippetName is the Caddy snippet name every protected site imports. It is
// "auth" — the concept (forward auth), never a provider name — so swapping the
// backing provider is a content change in one file, not a rename everywhere.
const AuthSnippetName = "auth"

// AuthSnippetFilename is the generated file holding the (auth) snippet. It sits
// directly in caddy/data/ (a sibling of splitdns.generated.caddy), so it is not
// picked up by the sites/*.caddy or tls/*.caddy globs and must be imported by
// name — which CaddyImportFile does, before the site blocks.
const AuthSnippetFilename = "splitdns.auth.generated.caddy"

// AuthSnippet renders the (auth) snippet file. When body is non-empty it is the
// user-provided forward-auth block (copied verbatim from defaults.auth_snippet);
// when empty, an empty (auth) {} stub is emitted. Every site block imports
// (auth) unconditionally, so the empty stub is a deliberate no-op: it lets a
// service opt in via `import auth` while global auth is off, and lets auth be
// turned on/off by changing this one file's content rather than rewriting sites.
func AuthSnippet(body string) string {
	inner := strings.TrimRight(body, "\n")
	if inner == "" {
		return fmt.Sprintf("%s\n(%s) {\n}\n", Header, AuthSnippetName)
	}
	// Indent each line of the provided body one tab into the snippet block.
	var b strings.Builder
	fmt.Fprintf(&b, "%s\n(%s) {\n", Header, AuthSnippetName)
	for _, line := range strings.Split(inner, "\n") {
		if line == "" {
			b.WriteString("\n")
			continue
		}
		b.WriteString("\t")
		b.WriteString(line)
		b.WriteString("\n")
	}
	b.WriteString("}\n")
	return b.String()
}

// TLSSnippetName derives the Caddy snippet name for a domain: tls_ followed by
// the domain with dots replaced by underscores (e.g. example.com ->
// tls_example_com). Deterministic and collision-free across TLDs.
func TLSSnippetName(domain string) string {
	return "tls_" + strings.ReplaceAll(domain, ".", "_")
}

// TLSSnippet renders the Caddy (tls_<domain>) snippet that points at the
// domain's wildcard cert. The cert path convention is fixed:
// /etc/caddy/certs/<domain>/{fullchain.cer,privkey.key} (design §4.2). The
// tool generates this so a domain needs no hand-written Caddyfile snippet.
func TLSSnippet(domain string) string {
	return fmt.Sprintf(
		"%s\n(%s) {\n\ttls /etc/caddy/certs/%s/fullchain.cer /etc/caddy/certs/%s/privkey.key\n}\n",
		Header, TLSSnippetName(domain), domain, domain)
}

// DNSRecord renders the dnsmasq directives for a service.
//
//   - local=/<fqdn>/ makes dnsmasq authoritative for the WHOLE name, so query
//     types with no local record — notably the HTTPS/SVCB (type 65) record —
//     return NODATA instead of being forwarded upstream and cached. Required:
//     address= alone only covers A/AAAA; without local=, dnsmasq forwards the
//     HTTPS query to Cloudflare, and SVCB-aware clients (Safari, Chrome/Edge)
//     follow its public endpoint hint, bypassing split-horizon. (Verified: with
//     local= type 65 is NODATA; without it, type 65 is the cached Cloudflare
//     record.)
//   - the A record points at hostIP (the host that RUNS the service).
//   - address=/<fqdn>/:: suppresses the public AAAA; :: (unspecified) is
//     correct, ::1 (loopback) is a bug (design §4.1).
func DNSRecord(fqdn, hostIP string) string {
	return fmt.Sprintf("%s\nlocal=/%s/\naddress=/%s/%s\naddress=/%s/::\n",
		Header, fqdn, fqdn, hostIP, fqdn)
}

// CaddySite renders the Caddy site block for a service. tlsImport is the
// snippet name (e.g. tls_example_com); backend is emitted verbatim as the
// reverse_proxy upstream (design §4.2). When auth is true, the site imports the
// (auth) forward-auth snippet before proxying — placed before reverse_proxy so
// Caddy runs the auth check first and only proxies on success. When authBackend
// is true (this service is the forward-auth portal), the reverse_proxy also
// preserves the inbound X-Forwarded-Host so post-login redirects target the
// original service, not the portal.
func CaddySite(fqdn, tlsImport, backend string, auth, authBackend bool) string {
	authLine := ""
	if auth {
		authLine = fmt.Sprintf("\timport %s\n", AuthSnippetName)
	}
	// The forward-auth backend (the Authelia portal) must preserve the inbound
	// X-Forwarded-Host through the reverse_proxy. When a protected service's
	// auth check hits this backend, Caddy's outer hop already set
	// X-Forwarded-Host to the *original* service host; a plain reverse_proxy
	// would reset it to this block's host (the auth domain), making Authelia
	// treat itself as the target and loop the post-login redirect. Preserving it
	// is safe: the value is whatever the trusted outer Caddy hop computed, not
	// anything a client can spoof.
	if authBackend {
		return fmt.Sprintf("%s\n%s {\n\timport %s\n%s\treverse_proxy %s {\n\t\theader_up X-Forwarded-Host {header.X-Forwarded-Host}\n\t}\n}\n",
			Header, fqdn, tlsImport, authLine, backend)
	}
	return fmt.Sprintf("%s\n%s {\n\timport %s\n%s\treverse_proxy %s\n}\n",
		Header, fqdn, tlsImport, authLine, backend)
}
